import { buildSectionPage } from '../../utils/section-page.utils.js';
import { ProjectsService } from '../../services/projects.service.js';
import '../log-viewer/log-viewer.component.js';
import type { LogViewer } from '../log-viewer/log-viewer.component.js';
import type { ScreenComponent } from '../../types/screen-component.js';

export class ProjectsLogsScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;

    setLoading(): void {}
    setError(err: unknown): void {}
    clearStatus(): void {}

    connectedCallback(): void {
        if (this.initialized) return;
        this.initialized = true;

        const page = buildSectionPage(this, 'Server Logs', 'projects', '/projects');
        const intro = document.createElement('p');
        intro.textContent = 'Filter by level or search by keyword. Tap an entry to expand context.';
        page.content.appendChild(intro);

        const logViewer = document.createElement('log-viewer') as LogViewer;
        logViewer.source = (filters) => ProjectsService.fetchMotivationLogs({
            level: filters.level,
            search: filters.search,
        });
        page.content.appendChild(logViewer);
    }
}

if (!customElements.get('projects-logs-screen')) {
    customElements.define('projects-logs-screen', ProjectsLogsScreen);
}
